import{_ as a,a as t,b as s,c as i,d as n,e as o}from"./chunks/手机端显示用户管理效果.D-1yQf5H.js";import{_ as d,o as l,c as r,a2 as p}from"./chunks/framework.DnrXFDHb.js";const I=JSON.parse('{"title":"IP Geolocation و User Management","description":"","frontmatter":{},"headers":[],"relativePath":"fa/Other/ip-geolocation-and-user-management.md","filePath":"fa/Other/ip-geolocation-and-user-management.md","lastUpdated":1781962217000}'),c={name:"fa/Other/ip-geolocation-and-user-management.md"};function u(g,e,h,m,b,f){return l(),r("div",null,[...e[0]||(e[0]=[p('<h1 id="ip-geolocation-و-user-management" tabindex="-1">IP Geolocation و User Management <a class="header-anchor" href="#ip-geolocation-و-user-management" aria-label="Permalink to &quot;IP Geolocation و User Management&quot;">​</a></h1><p>IP geolocation، IP addresses موجود در uploader records، login devices و logs مشابه را به approximate locations تبدیل می‌کند.</p><p>پس از configure شدن، admin panel می‌تواند origin مربوط به upload و access را واضح‌تر نشان دهد. User Management همچنین اجازه می‌دهد upload access مربوط به IP addresses مشکوک را block یا restore کنید.</p><h2 id="کجا-configure-کنیم" tabindex="-1">کجا Configure کنیم <a class="header-anchor" href="#کجا-configure-کنیم" aria-label="Permalink to &quot;کجا Configure کنیم&quot;">​</a></h2><p>باز کنید:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; IP Geolocation</span></span></code></pre></div><p><img src="'+a+`" alt="IP geolocation" loading="lazy"></p><h2 id="available-settings" tabindex="-1">Available Settings <a class="header-anchor" href="#available-settings" aria-label="Permalink to &quot;Available Settings&quot;">​</a></h2><p>flow جدید IP geolocation به‌جای تکیه روی یک map service، چند source را پشتیبانی می‌کند.</p><table tabindex="0"><thead><tr><th>Setting</th><th>Purpose</th></tr></thead><tbody><tr><td>IP geolocation language</td><td>انتخاب display language، مثل English، Simplified Chinese، Japanese، French و غیره.</td></tr><tr><td>MaxMind Account ID</td><td>MaxMind account ID برای MaxMind GeoLite Web Service.</td></tr><tr><td>MaxMind License Key</td><td>MaxMind License Key.</td></tr><tr><td>Tencent Map Key</td><td>Tencent Location Service key. برای Chinese addresses و mainland China IPs مفید است.</td></tr><tr><td>ipapi Key</td><td>APILayer ipapi key. IP geolocation چندزبانه را پشتیبانی می‌کند.</td></tr></tbody></table><p>فقط services موردنیازتان را پر کنید. لازم نیست همه fields configure شوند.</p><p>اگر هیچ key وارد نشود، ImgBed همچنان built-in free sources را امتحان می‌کند، اما stability، language support و precision ممکن است پایین‌تر از serviceهایی باشد که خودتان configure کرده‌اید.</p><h2 id="انتخاب‌های-پیشنهادی" tabindex="-1">انتخاب‌های پیشنهادی <a class="header-anchor" href="#انتخاب‌های-پیشنهادی" aria-label="Permalink to &quot;انتخاب‌های پیشنهادی&quot;">​</a></h2><p>اگر بیشتر به Chinese addresses نیاز دارید:</p><ol><li>IP geolocation language را روی Simplified Chinese بگذارید.</li><li>Tencent Map Key را configure کنید.</li><li>در صورت نیاز MaxMind یا ipapi را به‌عنوان fallback source اضافه کنید.</li></ol><p>اگر بیشتر به English یا multilingual addresses نیاز دارید:</p><ol><li>language موردنیاز را انتخاب کنید.</li><li>MaxMind Account ID و License Key را configure کنید.</li><li>اگر results چندزبانه بهتر می‌خواهید، ipapi Key اضافه کنید.</li></ol><h2 id="maxmind-setup" tabindex="-1">MaxMind Setup <a class="header-anchor" href="#maxmind-setup" aria-label="Permalink to &quot;MaxMind Setup&quot;">​</a></h2><p>MaxMind نیاز دارد به:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>MaxMind Account ID</span></span>
<span class="line"><span>MaxMind License Key</span></span></code></pre></div><p>Account ID را در MaxMind dashboard پیدا کنید و از License Keys page یک License Key بسازید.</p><p><img src="`+t+'" alt="MaxMind key config" loading="lazy"></p><p>پس از generation، Account ID و License Key را در ImgBed paste و save کنید.</p><p>پلن رایگان MaxMind برای استفاده روزمره مناسب است، اما request limits دارد. اگر quota تمام شود، ImgBed sources موجود دیگر را امتحان می‌کند.</p><h2 id="ipapi-setup" tabindex="-1">ipapi Setup <a class="header-anchor" href="#ipapi-setup" aria-label="Permalink to &quot;ipapi Setup&quot;">​</a></h2><p>ipapi از APILayer API Key استفاده می‌کند.</p><p>ipapi console را باز کنید و API Key نمایش‌داده‌شده را copy کنید.</p><p><img src="'+s+'" alt="ipapi config" loading="lazy"></p><p>آن را در field <code>ipapi Key</code> داخل ImgBed paste و save کنید.</p><p>ipapi IP geolocation چندزبانه را پشتیبانی می‌کند و وقتی می‌خواهید addresses به language انتخاب‌شده نمایش داده شوند مفید است. پلن رایگان آن هم request limits دارد. اگر quota تمام شود، ImgBed sources دیگر را امتحان می‌کند.</p><h2 id="tencent-map-key-setup" tabindex="-1">Tencent Map Key Setup <a class="header-anchor" href="#tencent-map-key-setup" aria-label="Permalink to &quot;Tencent Map Key Setup&quot;">​</a></h2><p>Tencent Map Key برای Chinese addresses، به‌خصوص mainland China IPs، مفید است.</p><p>هنگام ساخت key در Tencent Location Service، enable کنید:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>WebServiceAPI</span></span></code></pre></div><p>پس از ساخت، key را در <code>Tencent Map Key</code> paste و save کنید.</p><p>اگر فقط basic Chinese IP geolocation می‌خواهید، Tencent Map Key برای شروع کافی است.</p><h2 id="در-user-management-چه-چیزهایی-را-بررسی-کنیم" tabindex="-1">در User Management چه چیزهایی را بررسی کنیم <a class="header-anchor" href="#در-user-management-چه-چیزهایی-را-بررسی-کنیم" aria-label="Permalink to &quot;در User Management چه چیزهایی را بررسی کنیم&quot;">​</a></h2><p>User Management از بالای admin panel در دسترس است.</p><p><img src="'+i+'" alt="User management" loading="lazy"></p><p>User Management فعالیت upload را بر اساس IP نشان می‌دهد:</p><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td>IP source</td><td>source IP مربوط به uploader.</td></tr><tr><td>Address</td><td>approximate location به‌دست‌آمده از IP.</td></tr><tr><td>Total upload size</td><td>total file size آپلودشده توسط این IP.</td></tr><tr><td>Upload count</td><td>تعداد uploads از این IP.</td></tr><tr><td>Upload allowed</td><td>On یعنی uploads مجاز است. Off یعنی uploads blocked است.</td></tr></tbody></table><p>روی arrow سمت چپ کلیک کنید تا list مربوط به files upload شده توسط آن IP باز شود.</p><p>file list شامل file name، preview، file size، moderation result، file status و upload time است. اگر uploads مشکوک هستند، ابتدا IP را expand کنید، files را review کنید، سپس تصمیم بگیرید uploads بعدی block شوند یا نه.</p><p>اگر IP مشکوک است، <code>Upload allowed</code> را off کنید. uploads آینده از آن IP blocked خواهند شد.</p><h2 id="search،-sort-و-advanced-filters" tabindex="-1">Search، Sort و Advanced Filters <a class="header-anchor" href="#search،-sort-و-advanced-filters" aria-label="Permalink to &quot;Search، Sort و Advanced Filters&quot;">​</a></h2><p>بالای User Management می‌توانید بر اساس IP source یا address جست‌وجو کنید.</p><p>برای پیدا کردن recent uploaders، high-frequency uploaders یا high-usage IPs، بر اساس time، upload count یا total upload size sort کنید.</p><p>برای بررسی دقیق‌تر، advanced filters را باز کنید.</p><p><img src="'+n+'" alt="Advanced filters" loading="lazy"></p><p>Advanced filters این موارد را پشتیبانی می‌کند:</p><table tabindex="0"><thead><tr><th>Filter</th><th>Usage</th></tr></thead><tbody><tr><td>Time range</td><td>IPهایی را نشان می‌دهد که در period انتخاب‌شده files upload کرده‌اند.</td></tr><tr><td>Access status</td><td>بر اساس normal، blocked و states مشابه filter می‌کند.</td></tr><tr><td>Allow/block list</td><td>بر اساس allowlist، blocklist یا unset filter می‌کند.</td></tr><tr><td>File type</td><td>IPهایی را نشان می‌دهد که images، videos، audio، documents، code یا other files upload کرده‌اند.</td></tr><tr><td>File size</td><td>بر اساس uploaded file size range filter می‌کند.</td></tr><tr><td>Age rating</td><td>بر اساس unset، General، R12+، R16+، R18 و ratings مشابه filter می‌کند.</td></tr><tr><td>File status</td><td>برای بررسی abnormal files بر اساس current file status filter می‌کند.</td></tr></tbody></table><p>برای apply کردن، <code>Apply Filters</code> را بزنید. برای برگشت به همه data از <code>Reset</code> استفاده کنید.</p><h2 id="mobile-view" tabindex="-1">Mobile View <a class="header-anchor" href="#mobile-view" aria-label="Permalink to &quot;Mobile View&quot;">​</a></h2><p>در mobile، User Management به card layout تبدیل می‌شود.</p><p><img src="'+o+`" alt="Mobile user management" loading="lazy"></p><p>هر card شامل IP، address، total upload size، upload count و upload allowed switch است. بدون horizontal table scrolling می‌توانید users را manage کنید.</p><h2 id="اگر-location-اشتباه-به-نظر-می‌رسد" tabindex="-1">اگر Location اشتباه به نظر می‌رسد <a class="header-anchor" href="#اگر-location-اشتباه-به-نظر-می‌رسد" aria-label="Permalink to &quot;اگر Location اشتباه به نظر می‌رسد&quot;">​</a></h2><p>IP geolocation تقریبی است. آدرس دقیق خیابان نیست.</p><p>اگر user پشت proxy، data center، cloud server یا cross-border network باشد، location نمایش‌داده‌شده ممکن است با location واقعی متفاوت باشد.</p><p>از این feature برای فهم rough origin، پیدا کردن abnormal uploads و کمک به blocking decisions استفاده کنید. آن را tracking دقیق در نظر نگیرید.</p><h2 id="common-cases" tabindex="-1">Common Cases <a class="header-anchor" href="#common-cases" aria-label="Permalink to &quot;Common Cases&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Case</th><th>Meaning</th></tr></thead><tbody><tr><td>Address خالی است</td><td>IP شاید هنوز resolve نشده، یا source فعلی موقتاً unavailable است.</td></tr><tr><td>Address language اشتباه است</td><td>IP geolocation language و source پشتیبان آن language را بررسی کنید.</td></tr><tr><td>Address یک data center نشان می‌دهد</td><td>بسیاری از proxies، cloud servers و crawlers به‌صورت data center یا ISP addresses دیده می‌شوند.</td></tr><tr><td>Upload count بالاست</td><td>این IP را با دقت review کنید و در صورت نیاز uploads را block کنید.</td></tr><tr><td>Total upload size زیاد است</td><td>sort یا filter کنید، IP را expand کنید و specific files را inspect کنید.</td></tr><tr><td>نیاز به restore پس از blocking</td><td><code>Upload allowed</code> را دوباره on کنید.</td></tr></tbody></table><h2 id="quick-flow" tabindex="-1">Quick Flow <a class="header-anchor" href="#quick-flow" aria-label="Permalink to &quot;Quick Flow&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>IP Geolocation را در Other Settings باز کنید</span></span>
<span class="line"><span>-&gt; IP geolocation language را انتخاب کنید</span></span>
<span class="line"><span>-&gt; credentials مربوط به MaxMind, Tencent Map یا ipapi را در صورت نیاز وارد کنید</span></span>
<span class="line"><span>-&gt; settings را save کنید</span></span>
<span class="line"><span>-&gt; User Management را باز کنید</span></span>
<span class="line"><span>-&gt; IP source, address, total upload size و upload count را review کنید</span></span>
<span class="line"><span>-&gt; برای پیدا کردن abnormal IPs از search, sort یا advanced filters استفاده کنید</span></span>
<span class="line"><span>-&gt; uploads را در صورت نیاز allow یا block کنید</span></span></code></pre></div>`,64)])])}const v=d(c,[["render",u]]);export{I as __pageData,v as default};
